    #[tokio::test]
    async fn test_merge_retry_nonexistent_entry() {
        let dir = tempfile::tempdir().unwrap();
        let (_store, coord) = setup_coordinator(dir.path()).await;

        let id = uuid::Uuid::now_v7();
        let count = merge_retry(&coord, &[id]).unwrap();
        assert_eq!(count, 0);
    }

